/// Helper: decode a hex string (may contain whitespace) into bytes.
pub fn hex_to_bytes(s: &str) -> Vec<u8> {
    let cleaned: String = s.chars().filter(|c| !c.is_whitespace()).collect();
    (0..cleaned.len())
        .step_by(2)
        .map(|i| u8::from_str_radix(&cleaned[i..i + 2], 16).expect("valid hex"))
        .collect()
}

pub fn leaf_der() -> Vec<u8> { hex_to_bytes(CERT_LEAF_HEX) }
pub fn int1_der() -> Vec<u8> { hex_to_bytes(CERT_INT1_HEX) }
pub fn int2_der() -> Vec<u8> { hex_to_bytes(CERT_INT2_HEX) }
pub fn root_der() -> Vec<u8> { hex_to_bytes(CERT_ROOT_HEX) }

